SELECT MAX(rank) AS highest_rank, MAX(points) AS highest_points
FROM rankings
WHERE user_id = 0;

SELECT COUNT(*) AS total_games_played
FROM gaming_history
WHERE user_id = 0;

SELECT SUM(quantity) AS total_equipped_items
FROM user_items
WHERE user_id = 0 AND equipped = 1;

SELECT user_id, COUNT(*) AS total_games_played
FROM gaming_history
GROUP BY user_id;
